async (params, browser) => {
  // Open Gmail
  await browser.open('https://mail.google.com/mail/u/0/#inbox')

  // Wait for Gmail to load
  await browser.waitForSelector('input[aria-label=\'Search mail\']', 15000)

  // Let Gmail fully initialize
  await browser.wait(2000)

  // Search for the email by subject
  const search_email = await browser.evaluate(`const searchInput = document.querySelector('input[aria-label="Search mail"]'); if (searchInput) { searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); searchInput.select(); document.execCommand('insertText', false, \`subject:' + params.subject + '\`); await new Promise(r => setTimeout(r, 300)); searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true })); } return { searched: true }`)

  // Wait for search results
  await browser.wait(3000)

  // Click on the matching email
  const click_email = await browser.evaluate(`const rows = document.querySelectorAll('tr.zA'); if (rows.length === 0) return { error: 'No emails found matching the subject' }; const target = params.subject.toLowerCase(); let bestMatch = rows[0]; for (const row of rows) { const subjectEl = row.querySelector('.bog span, .y6 span'); if (subjectEl && subjectEl.textContent.trim().toLowerCase().includes(target)) { bestMatch = row; break; } } bestMatch.click(); return { clicked: true }`)

  // Wait for email to open
  await browser.wait(2000)

  // Wait for email body to render
  await browser.waitForSelector('.a3s, .ii.gt, [data-message-id] .a3s', 10000)

  // Extract full email content
  const email_content = await browser.evaluate(`const subjectEl = document.querySelector('h2.hP, .ha h2'); const fromEl = document.querySelector('.gD[email], .go .gD'); const toEl = document.querySelector('.g2 span[email], .g2 .gD'); const dateEl = document.querySelector('.g3, .gK span[title], .gK span'); const bodyEl = document.querySelector('.a3s.aiL, .a3s, .ii.gt'); return { from: fromEl ? (fromEl.getAttribute('email') || fromEl.textContent.trim()) : '', to: toEl ? (toEl.getAttribute('email') || toEl.textContent.trim()) : '', subject: subjectEl ? subjectEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('title') || dateEl.textContent.trim()) : '', body: bodyEl ? bodyEl.innerText.trim().substring(0, 5000) : '' }`)

  return email_content
}
